def buscar_livros(termo=""):
    if not termo:
        return biblioteca

    termo = str(termo).lower()
    resultados = []

    for livro in biblioteca:
        if (termo in str(livro["titulo"]).lower() or
                termo in str(livro["autor"]).lower() or
                termo in str(livro["categoria"]).lower() or
                termo in str(livro["ano"])):
            resultados.append(livro)

    return resultados